const p = msg.payload;
if (!p || !p.action) return null;

if (p.action !== 'set_horas' && p.action !== 'set_absoluto') return null;

let desde, hasta;

if (p.action === 'set_horas') {
    const horas = parseFloat(p.value) || 0.25;
    hasta = new Date().toISOString();
    desde = new Date(Date.now() - horas * 3600000).toISOString();
} else {
    desde = p.value.desde;
    hasta = p.value.hasta;
}

const savedState = p.value && typeof p.value === 'object' ? p.value : {};
const colsAct = savedState.colsAct || ['circuito-a'];

const inClause = colsAct.map(c => `'${c}'`).join(', ');

msg.payload = `
    SELECT time, measurement, power_a, power_b, power_c, voltage_a, current_a, temperature
    FROM metricas
    WHERE time >= '${desde}'
      AND time <= '${hasta}'
      AND measurement IN (${inClause})
    ORDER BY measurement, time ASC
`;

msg.colecciones = colsAct;
msg.desde = desde;
msg.hasta = hasta;
return msg;

// ── Paleta de colores ────────────────────────────────────────────────────
const paleta = [
    '#58a6ff','#3fb950','#f78166','#d2a8ff','#ffa657',
    '#79c0ff','#56d364','#ff7b72','#bc8cff','#ffb366',
    '#388bfd','#2ea043','#da3633','#8957e5'
];

const toKW = w => (w != null) ? parseFloat((w / 1000).toFixed(3)) : null;
const toF  = (v, d) => (v != null) ? parseFloat(parseFloat(v).toFixed(d)) : null;
const toMs = d => new Date(d.time).getTime();

const mkSerie = (name, metric, yIdx, color, data, dash) => ({
    name, metric,
    type: 'line',
    yAxisIndex: yIdx,
    data,
    smooth: true,
    connectNulls: false,
    lineStyle: { width: 1, color, ...(dash ? { type: dash } : {}) },
    itemStyle: { color }
});

// PostgreSQL devuelve array plano de rows
const rows        = msg.payload || [];
const colecciones = msg.colecciones || [];
const series      = [];
const colLabels   = {};

// Agrupar rows por device
const porDevice = {};
rows.forEach(row => {
    const key = row.measurement || row.device;
    if (!porDevice[key]) porDevice[key] = [];
    porDevice[key].push(row);
});

let colIdx = 0;
for (const col of colecciones) {
    const docs = porDevice[col] || [];
    if (!docs.length) { colIdx++; continue; }

    const label = col;
    const color = paleta[colIdx % paleta.length];
    const m0    = docs[0];

    // kW total
    if (m0.power !== undefined || m0.power_a !== undefined) {
        const data = docs.map(d => {
            const w = (d.power != null) ? d.power
                    : ((d.power_a || 0) + (d.power_b || 0) + (d.power_c || 0));
            return [toMs(d), toKW(w)];
        }).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW', 'kW', 0, color, data));
    }
    if (m0.power_a !== undefined && m0.power_a !== null) {
        const data = docs.map(d => [toMs(d), toKW(d.power_a)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW-A', 'kW-A', 0, color, data, 'dashed'));
    }
    if (m0.power_b !== undefined && m0.power_b !== null) {
        const data = docs.map(d => [toMs(d), toKW(d.power_b)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW-B', 'kW-B', 0, color, data, 'dotted'));
    }
    if (m0.power_c !== undefined && m0.power_c !== null) {
        const data = docs.map(d => [toMs(d), toKW(d.power_c)]).filter(p => p[1] !== null);
        if (data.length) series.push(mkSerie(label + ' · kW-C', 'kW-C', 0, color, data, 'dotted'));
    }
    if (m0.temperature !== undefined && m0.temperature !== null) {
        const data = docs.map(d => [toMs(d), toF(d.temperature, 1)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie(label + ' · °C', '°C', 1, color, data));
    }
    if (m0.voltage_a !== undefined && m0.voltage_a !== null) {
        const data = docs.map(d => [toMs(d), toF(d.voltage_a, 1)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie(label + ' · V', 'V', 2, color, data));
    }
    if (m0.current_a !== undefined && m0.current_a !== null) {
        const data = docs.map(d => [toMs(d), toF(d.current_a, 2)]).filter(p => p[1] !== null && p[1] > 0);
        if (data.length) series.push(mkSerie(label + ' · A', 'A', 3, color, data));
    }

    colLabels[label] = col;
    colIdx++;
}

msg.topic   = 'insight/data';
msg.payload = { series, colLabels };
return msg;

const d = msg.payload;
if (!d) return null;

const measurement = d.measurement || 'circuito-a';

msg.payload = `
    INSERT INTO metricas (time, measurement, power_a, power_b, power_c, voltage_a, current_a, temperature)
    VALUES (
        NOW(),
        '${measurement}',
        ${d.power_a || 0},
        ${d.power_b || 0},
        ${d.power_c || 0},
        ${d.voltage_a || 0},
        ${d.current_a || 0},
        ${d.temperature || 0}
    )
`;
return msg;
